import React, { useState } from 'react';
import Swal from 'sweetalert2';

const HotelAdminRegister = ({ onSuccess, onBack }) => {
  const [form, setForm] = useState({
    name: '',
    email: '',
    password: '',
    hotelName: ''
  });

  const handleSubmit = (e) => {
    e.preventDefault();

    // fake submit (replace with API later)
    Swal.fire({
      icon: 'success',
      title: 'Submitted!',
      text: 'Your account is pending system admin approval.'
    });

    onSuccess();
  };

  return (
    <div className="min-h-screen flex items-center justify-center bg-slate-950 text-white">
      <div className="bg-white/10 p-8 rounded-2xl w-[400px]">

        <h2 className="text-2xl mb-4 font-bold">Hotel Partner Registration</h2>

        <form onSubmit={handleSubmit} className="space-y-3">

          <input
            placeholder="Full Name"
            className="w-full p-2 rounded bg-black/40"
            onChange={(e) => setForm({ ...form, name: e.target.value })}
          />

          <input
            placeholder="Email"
            className="w-full p-2 rounded bg-black/40"
            onChange={(e) => setForm({ ...form, email: e.target.value })}
          />

          <input
            type="password"
            placeholder="Password"
            className="w-full p-2 rounded bg-black/40"
            onChange={(e) => setForm({ ...form, password: e.target.value })}
          />

          <input
            placeholder="Hotel Name"
            className="w-full p-2 rounded bg-black/40"
            onChange={(e) => setForm({ ...form, hotelName: e.target.value })}
          />

          <button className="w-full bg-cyan-500 p-2 rounded">
            Submit Application
          </button>

        </form>

        <button onClick={onBack} className="mt-3 text-sm text-gray-400">
          Back
        </button>

      </div>
    </div>
  );
};

export default HotelAdminRegister;
